/** Category-level fallback for products the sheet marks "All" rather than listing individual model codes. */
export const categorySpecSheet: { socketType: string; specs: SpecRow[] }[] = [
  { socketType: 'Telephone Socket', specs: [{ label: 'Case Material', value: 'PC' }, { label: 'Component Material', value: 'Brass' }] },
  { socketType: 'TV / Dish Socket', specs: [{ label: 'Case Material', value: 'PC' }, { label: 'Component Material', value: 'Brass' }] },
  { socketType: 'Internet/Data Socket', specs: [{ label: 'Case Material', value: 'PC' }, { label: 'Component Material', value: 'Brass' }] },
];

export const getSpecSheetRows = (modelNo: string, socketType?: string): SpecRow[] | undefined => {
  const byModel = modelSpecSheet[modelNo.toUpperCase()];
  if (byModel) return byModel;
  if (socketType) return categorySpecSheet.find((c) => c.socketType === socketType)?.specs;
  return undefined;
};
